export type PatternCategory =
  | "spaceships"
  | "oscillators"
  | "still-lifes"
  | "seeds"
  | "guns"
  | "mega";

export type LifePattern = {
  id: string;
  name: string;
  description: string;
  category: PatternCategory;
  cells: readonly [number, number][];
};

const fromRows = (
  category: PatternCategory,
  id: string,
  name: string,
  description: string,
  rows: readonly string[],
): LifePattern => ({
  id,
  name,
  description,
  category,
  cells: rows.flatMap((row, y) =>
    [...row].flatMap((cell, x) =>
      cell === "O" ? [[x, y] as [number, number]] : [],
    ),
  ),
});

const fromRle = (
  category: PatternCategory,
  id: string,
  name: string,
  description: string,
  rle: string,
): LifePattern => {
  const cells: [number, number][] = [];
  let x = 0;
  let y = 0;
  let count = "";
  const takeCount = () => {
    const value = count === "" ? 1 : Number(count);
    count = "";
    return value;
  };

  for (const token of rle.replace(/\s/g, "")) {
    if (/\d/.test(token)) {
      count += token;
    } else if (token === "b") {
      x += takeCount();
    } else if (token === "o") {
      const run = takeCount();
      for (let offset = 0; offset < run; offset += 1)
        cells.push([x + offset, y]);
      x += run;
    } else if (token === "$") {
      y += takeCount();
      x = 0;
    } else if (token === "!") {
      break;
    }
  }

  return { id, name, description, category, cells };
};

